# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

import logging
import json
from flask import Flask, request, Response, make_response
from functools import wraps
import jwt as pyjwt # pip install jwt

app = Flask(__name__)

logging.basicConfig(level=logging.DEBUG)

@app.route('/v1', methods=['POST'])
def gateway():
    # Get the token from the header. 
    try:
        token = request.headers['Authorization']
    except KeyError as error:
         logging.debug(error)
         return Response(status=403, response="Forbidden.")

    # Verify that this is a JWT token. 
    try:
       pyjwt.decode(token, verify=False)
    except Exception as error:
         logging.info('No Token found or not a valid Token.')
         return Response(status=500, response=str(error))
    
    # Extract the subject (User ID).
    try:
        data = pyjwt.decode(token, verify=False)['sub']
    except Exception as error:
       logging.debug("Unable to extract the user.")
       return Response(status=422)

    # Get the token type and check for appropriate permissions. 
    try:
        tokenType = request.headers['Authorization'].split()[0]
        if tokenType != 'Bearer':
            raise ValueError
    except Exception as error:
           logging.debug("Invalid Type for Token")
           return Response(status=500, response="Invalid Type")

    # Build a response and set the headers accordingly. 
    try:
        response = make_response(jsonify({
            "success": True,
            "response":"Authenticated.",
            'token': token, 
            'subject': data}))
        response.headers['Content-Type']='application/json'
        return response
    except Exception as error:
           logging.debug("No Headers set in Response")
           return Response(status=422)


if __name__ == '__main__':
     app.run()

